args.sparql:
SELECT ?trackLabel WHERE {
  ?song wdt:P31 wd:Q17559915;
        rdfs:label "Piano Man"@en.
  ?song wdt:P170 ?album.
  ?album wdt:P175 ?track_number;
         wdt:P195 ?track.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". ?track rdfs:label ?trackLabel. }
}
ORDER BY ?track_number
OFFSET 5
LIMIT 1

SELECT DISTINCT ?album WHERE {
  ?album wdt:P195 ?track.
  ?track rdfs:label "Piano Man"@en.
  ?album wdt:P31 wd:Q386724.
}
